import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"87. Senior Allowance Mho","description":"","frontmatter":{"title":"87. Senior Allowance Mho","eba":"Mental Health Services 2024-2028","topics":["allowances","preliminary","classifications"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/87-senior-allowance-mho.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/87-senior-allowance-mho.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/allowances/87-senior-allowance-mho.md"};function i(l,e,s,h,c,p){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_87-senior-allowance-mho" tabindex="-1">87. Senior Allowance Mho <a class="header-anchor" href="#_87-senior-allowance-mho" aria-label="Permalink to &quot;87. Senior Allowance Mho&quot;">​</a></h1><p><strong>87.1</strong> Subject to clause 87.2 below, a MHO who is appointed as a &#39;Senior&#39; will have their classification preceded by the word &#39;Senior&#39; and paid an allowance of 10% to be calculated upon the base rate payable in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> in addition to any other allowance to which the Employee is entitled.</p><p><strong>87.2</strong> Appointment to a classification preceded by the word &#39;Senior&#39; will only be made where the work performed by such person represents a net addition to the work value of the substantive role in a similar area or areas. Indicative of a net addition to work value may include the performance of additional duties or functions, the assignment of a special project or an increased emphasis on the performance of core functions already undertaken by Employees in that classification.</p><p><strong>87.3</strong> A net addition to the work value of the substantive role of an Employee would be characterised by:</p><p><strong>(a)</strong> the additional functions or duties are a regular and on-going requirement; and</p><p><strong>(b)</strong> experience in the role commensurate with this clause, coupled with on-the-job training where provided by the Employer; and</p><p><strong>(c)</strong> the necessity for additional training in a particular aspect of the role above that is required to fulfil the role of an Employee employed in a similar area or areas; and</p><p><strong>(d)</strong> a greater level of judgment is required from the Employee whereby they is capable of making independent decisions to a degree not generally expected of an Employee employed in a similar area or areas; and</p><p><strong>(e)</strong> a higher degree of accountability is expected for work undertaken, such that the Employee is clearly performing at a level above that of their peers employed in a similar area or areas by the Employer where the requirements of sub-clause (b) above continue to be met.</p><p><strong>87.4</strong> Where the Employer no longer requires the Employee to perform the extra duties (that attract the allowance), the Employee will be informed, and consultation will occur regarding scope for other extra duties to be identified that the Employer may require the Employee to perform which may attract payment of the allowance.</p>',10)])])}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
